INSERT OR REPLACE INTO reference_materials (id, source_file, chunk_index, content, tokens) VALUES ('ref_cb52fb6fb03f', '2019年实务真题及答案解析.pdf', 4, '# 权利要求书

1. 一种压蒜器，主要由上压杆（1）和下压杆（2）构成，其特征在于，上压杆（1）和下压杆（2）活动连接，上压杆（1）靠近前端的位置设有压蒜部件（3），下压杆（2）上设有与压蒜部件（3）相对应的压筒（4），压筒（4）上端开口，压筒（4）底部设有多个出蒜孔（5）。  
2. 根据权利要求 1 所述的压蒜器，其特征在于：上压杆（1）前端与下压杆（2）前端活动连接。  
3. 根据权利要求 2 所述的压蒜部件，其特征在于：所述压蒜部件（3）包括压臂（31）和固定连接在压臂（31）下端的压盘（32），所述压臂（31）的上端与上压杆（1）活动连接。  
4. 根据权利要求 2 或 3 所述的压蒜部件，其特征在于：所述压盘（32）上设有多个压蒜齿（33）。', 334);
INSERT OR REPLACE INTO reference_materials (id, source_file, chunk_index, content, tokens) VALUES ('ref_5988e48cad96', '2019年实务真题及答案解析.pdf', 6, '# 压蒜器

本实用新型涉及一种用于将蒜瓣压制成蒜泥的压蒜器。

大蒜是一种常用的调味食材，在将蒜瓣制成蒜泥时，传统的方法是采用捣杆与瓦罐配合将蒜瓣捣成蒜泥。目前市面上有一种压蒜器，可较传统方法更为方便省力地获得蒜泥。该压蒜器包括上压杆1''和下压杆2''，上压杆1''的端部设有压头3''，下压杆2''的端部设有与上述压头3''相配合的压筒4''，上压杆1''和下压杆2''在中间铰接起来形成钳子的形状。使用时，将蒜瓣放在压筒4''内，用手握住压杆，便可利用杠杆原理将蒜瓣压碎。

但是，该压蒜器用于挤压配合的压头 3’ 和压筒 4’ 分开的角度有限，蒜瓣较大时不易放入，而且压杆长度有限，挤压较大的蒜瓣时仍然比较费劲，

本实用新型的目的在于提供一种压蒜器，该压蒜器具有操作方便、节省力气的特点。

图 1 是现有技术的压蒜器的示意图。

图 2 是本实用新型的压蒜器实施例的示意图。

图 3 是本实用新型的压蒜器改进实施例的示意图。

如图 2 所示，本实用新型的压蒜器主要由上压杆 1 和下压杆 2 组成，上压杆 1 的前端与下压杆 2 的前端活动连接。上压杆 1 靠近前端的位置设有压蒜部件 3，所述压蒜部件 3 包括压臂 31 和固定连接在压臂 31 下端的压盘 32。下压杆 2 靠近前端的位置设有与压件部件 3 相对应的压筒 4，压筒 4 与下压杆 2 一体成型，其形状为上端开口的筒状体，压筒 4 底部具有多个圆形的出蒜孔 5，这些出蒜孔 5 间隔均匀地分布在压筒 4 的底面上。压蒜部件 3 与上压杆 1 之间最好采用活动连接的方式，例如，上压杆 1 底部靠近前端的位置设有一固定支座 6，压蒜部件 3 的压臂 31 通过销轴 7 与所述固定支座 6 连接。压臂 31 与固定支座 6 也可以通过其他方式活动连接，例如铆钉连接、螺栓连接等。', 781);
INSERT OR REPLACE INTO reference_materials (id, source_file, chunk_index, content, tokens) VALUES ('ref_c6b2a94a22b2', '2019年实务真题及答案解析.pdf', 7, '上压杆 1 底部靠近前端的位置设有一固定支座 6，压蒜部件 3 的压臂 31 通过销轴 7 与所述固定支座 6 连接。压臂 31 与固定支座 6 也可以通过其他方式活动连接，例如铆钉连接、螺栓连接等。

上述实施例中压蒜器的压盘 32 的下表面为平面，在使用时，压蒜器将蒜瓣压扁后，仍有部分蒜瓣被压成饼状被留在压筒 4 内，即便反复施力挤压扔无法将残留的蒜瓣挤碎并排出压筒 4。为进一步解决蒜瓣残留的问题。如图 3 所示，在压盘 32 的下表面上设置多个与出蒜孔 5 对应的压蒜齿 33，所述多个压蒜齿 33 间隔均匀地分布在压盘 32 的下表面上，其横截面直径小于出蒜孔 5 的内径，当压盘 32 置入压筒 4 内时，压蒜齿 33 与出蒜孔 5 一一对应，从而对蒜泥挤压更加充分，提高了蒜泥的挤出效率。

具体操作过程如下，首先一手握住下压杆 2，将上压杆 1 向上抬起，使得压盘 32 离开压筒 4，之后将蒜瓣放入压筒 4 内，将上压杆 1 下压，在上压杆 1 向下运动的过程中，压盘 32 进入压筒 4，对蒜瓣进行挤压，压蒜齿 33 将蒜泥从出蒜孔 5 挤出。

虽然本实用新型同样是利用杠杆原理将蒜瓣压碎，但由于将支点的位置调整到上、下压杆的前端，本实用新型的压蒜器相比于现有的压蒜器操作更为省力，不需施加很大的握压力即可将蒜瓣压碎成蒜泥；而且，压盘32上设置多个压蒜齿33也可以进一步提高蒜泥的挤出效率。

