INSERT OR REPLACE INTO reference_materials (id, source_file, chunk_index, content, tokens) VALUES ('ref_f4790097d5db', '2019年实务真题及答案解析.pdf', 25, '# （一）试卷分析

2019 年专利代理实务考试试题包括无效部分和新申请撰写部分，共有五道题目。

第一题、第二题是无效实务部分。第一题要求应试者根据客户提供的资料具体分析客户所撰写的无效宣告请求书中的各项理由是否成立，并将具体意见以信函的形式提交给客户，第二题要求应试者根据客户提供的资料为客户撰写一份无效宣告请求书。

第三题至第五题为申请实务部分。第三题为撰写权利要求书，第四题要求应试者分析其在第三题中撰写的独立权利要求相对于现有技术是否具备新颖性和创造性，第五题要求应试者撰写分案申请的独立权利要求，并陈述分案或合案申请的理由。

2019 年的试题无效部分与 2016 年、2018 年无效部分出题思路完全相同，均为先分析客户自行撰写的无效请求书中观点是否正确，再撰写正确的无效请求书。

2019 年试题撰写部分与 2012-2014、2018 年出题思路相同，均为考查并列发明点撰写两件或两件以上专利申请。', 412);
INSERT OR REPLACE INTO reference_materials (id, source_file, chunk_index, content, tokens) VALUES ('ref_467b610d9962', '2019年实务真题及答案解析.pdf', 28, '# 1、阅读步骤

解答第一题要需要阅读客户所撰写的无效宣告请求书（附件 2），附件 1（涉案专利）以及客户提供的对比文件 1-2。

阅读顺序应当为：附件 1（涉案专利）、对比文件 1、对比文件 2、无效请求书（附件 2）。', 113);
INSERT OR REPLACE INTO reference_materials (id, source_file, chunk_index, content, tokens) VALUES ('ref_d516003f1fed', '2019年实务真题及答案解析.pdf', 29, '# 2、时间判断

在时间方面，需要考查客户提供的对比文件是否构成涉案专利的现有技术，或者是否属于申请在先、公开（公告）在后的专利申请或者专利文件

对比文件 1 的申请日为 2017 年 11 月 22 日，公告日为 2018 年 06 月 30 日，涉案专利的申请日为 2017 年 12 月 12 日，因此，对比文件 1 属于申请在先、公开（公告）在后的中国实用新型专利文件，仅能用于评价权利要求的新颖性。

对比文件 2 的公告日为 2013 年 03 月 23 日，早于涉案专利的申请日 2017 年 12 月 12 日，在时间上构成了涉案专利的现有技术，可以用于评价权利要求的新颖性和创造性。', 302);
INSERT OR REPLACE INTO reference_materials (id, source_file, chunk_index, content, tokens) VALUES ('ref_d1896e2fd28b', '2019年实务真题及答案解析.pdf', 30, '# 3、内容判断

在分析客户提供的无效请求书之前，考生应当尽量能够自行分析涉案专利的权利要求书存在的缺陷，以免被客户思路带偏。

（1）权利要求 1 与对比文件 1 内容对比

<table><tr><td>涉案专利权利要求1</td><td>对比文件1</td><td>比较结论</td></tr><tr><td>一种压蒜器,主要由上压杆(1)和下压杆(2)构成,上压杆(1)和下压杆(2)活动连接</td><td>一种压蒜器,有两个手柄3(从图中看上下设置),两个手柄3通过连接孔用铆钉4连接起来</td><td>实质相同</td></tr><tr><td>上压杆(1)靠近前端的位置设有压蒜部件(3)</td><td>一个手柄3的前端压头1</td><td>实质相同</td></tr><tr><td>下压杆(2)上设有与压蒜部件(3)相对应的压筒(4)</td><td>一个手柄前端设有压槽2</td><td>实质相同</td></tr><tr><td>压筒(4)上端开口</td><td>压槽2顶部开口</td><td>相同</td></tr><tr><td>压筒(4)底部设有多个出蒜孔(5)</td><td>压槽底部均布有多个漏孔5</td><td>相同</td></tr><tr><td><img src="images/a8ac6417afdbfb0cdae903ba4cfacb00a114d8edcae393d270cc07ac6d1bf767.jpg"/></td><td><img src="images/e3825c3f424e5dc7ebcb271f466ed5ac6047daeb9e07ee4c0b0bd55dcbca401f.jpg"/></td><td></td></tr></table>', 765);
