INSERT OR REPLACE INTO reference_materials (id, source_file, chunk_index, content, tokens) VALUES ('ref_622e7d0a929d', '2019年实务真题及答案解析.pdf', 34, '></td><td></td></tr></table>

对比可见，权利要求 2、3 的附加特征均被对比文件 2 公开，权利要求 2、3 不具有新颖性。

（5）权利要求 4 与对比文件 2 的比较

<table><tr><td>涉案专利权利要求</td><td>对比文件2</td><td>比较结果</td></tr><tr><td>4、根据权利要求2或3所述的压蒜部件,其特征在于:所述压盘(32)上设有多个压蒜齿(33)。</td><td>第一压板无凸起,第二压板上设置凸起,疏通堵塞的漏孔</td><td rowspan="2">结构和作用均不同</td></tr><tr><td><img src="images/27dbc456e53719f44319ed6b18def78af8d0e1b86ac38e9e6bc9aa7717967c21.jpg"/></td><td><img src="images/4e2f8b73c519c34b486cd1c26e180349e63cf4c8c3d4f4b1146d9ad35c1c4e72.jpg"/></td></tr></table>

对权利要求 4 与对比文件 2 的比较，有如下四种观点：

① 观点 1：权利要求 4 不具有新颖性

通常初学者和有一定实践经验的应试者会认为权利要求 4 没有新颖性。

初学者会认为，对比文件 2 公开了第二压板上设置有凸起 8，公开了权利要求 4 的附加技术特征，在权利要求 1、2、3 均无新颖性的情况下，权利要求 4 也没有新颖性。

实践经验丰富的应试者会认为，如果将对比文件 2 的第二压板转向下，用第二压板压蒜，既能把蒜压碎，又能把残留蒜末清除，因此权利要求 4 没有新颖性。', 748);
INSERT OR REPLACE INTO reference_materials (id, source_file, chunk_index, content, tokens) VALUES ('ref_209cf047279a', '2019年实务真题及答案解析.pdf', 35, '均无新颖性的情况下，权利要求 4 也没有新颖性。

实践经验丰富的应试者会认为，如果将对比文件 2 的第二压板转向下，用第二压板压蒜，既能把蒜压碎，又能把残留蒜末清除，因此权利要求 4 没有新颖性。

以上两种看法都不正确。权利要求 1-3 对比分析新颖性时，和涉案专利压盘对应的是对比文件 2 中的第一压板，第一压板是平的，不带凸起。第二压板并不能替代第一压板。因此，对比文件 2 并未公开在第一压板上设置凸起，权利要求 4 有新颖性。

② 观点 2：权利要求 4 不具有创造性

大部分认真学习过历年试题的学员都会认为权利要求 4 不具有创造性（权利要求 1-3 均为无新颖性，该轮到权利要求没有创造性了，且大部分学员都联想到了 2016 年茶壶搅拌部可拆卸、搅拌棒可拆卸两个实施例的组合）。理由如下：

对比文件 2 的一部分内容公开了第一压板，但是没有公开在第一压板上设置压蒜齿，另外一部分【请注意，不是第一实施例、第二实施例】公开了第二压板上设置凸起，凸起在第二压板上起的作用是，当出现细碎蒜粒堵塞漏孔时，第二压板上的凸起穿透压料筒 5 底部的对应漏孔，从而疏通堵塞的漏孔。涉案专利权利要求 4 中，挤出蒜瓣残留，进一步提高蒜泥的挤出效率，二者实质相同。因此对比文件 2 的第二压板给出启示，本领域技术人员为了挤出蒜瓣残留，能想到将第二压板上设置的凸起设置到第一压板上，从而得到权利要求 4 的技术方案，因此权利要求 4 显而易见，不具有创造性。

上述观点实际上没有理解对比文件 2 的技术内容。对比文件 2 上压杆要旋转 360 度，从压料筒的下方往上疏通堵塞。考虑到考场时间紧张，对技术理解有偏差情有可原。', 712);
INSERT OR REPLACE INTO reference_materials (id, source_file, chunk_index, content, tokens) VALUES ('ref_2510b7459991', '2019年实务真题及答案解析.pdf', 36, '# ③ 观点 3：因凸齿作用不同，权利要求 4 具有创造性

观点 3 认为，涉案专利权利要求 4 中，压蒜齿的作用是挤出蒜瓣残留，提高蒜泥挤出效率，而第二压板上设置凸起的作用是疏通堵塞的漏孔，二者作用不同，因此权利要求 4 有创造性。

这种分析结论是对的，但是分析过程略有错误。挤出残留，提高效率，疏通漏孔，只是说法不一样，并非技术特征本身造成的（考生可对比2013年试题，空气流通和有助于套设垃圾袋不仅仅是表达不同，垃圾箱在固液分离的情况下设置通风孔有内外循环有因果关系，垃圾桶底部设置通孔和方便套设垃圾袋有因果关系），上述作用实质上是相同的。

持此观点的学员实际上并没有发现对比文件2上压杆要旋转360度，从压料筒的下方往上疏通堵塞。', 322);
INSERT OR REPLACE INTO reference_materials (id, source_file, chunk_index, content, tokens) VALUES ('ref_7c076987b8fa', '2019年实务真题及答案解析.pdf', 37, '# ④ 观点 4：疏通结构不同，因而权利要求 4 有创造性

观点 4 认为，涉案专利是用一个压盘捣蒜，而对比文件 2 先用第一压板（平板）捣蒜，当出现细碎蒜粒堵塞漏孔时，旋转上压杆，用第二压板的凸起从压料筒底部疏通，因而对比文件 2 和权利要求 4 的技术方案在结构、作用上均不同，因此权利要求 4 具有创造性。

观点 4 是最正确的，但是考场时间有限，且试题材料描述并不清楚，能够分析得十分精确比较困难。', 205);
INSERT OR REPLACE INTO reference_materials (id, source_file, chunk_index, content, tokens) VALUES ('ref_f47097d32eeb', '2019年实务真题及答案解析.pdf', 39, '# 1、对于理由1的分析

客户认为，权利要求 1 不具有新颖性的结论是成立的。但理由 1 中在论述权利要求 1 不具备新颖性的原因时，指出 “对比文件 1 作为现有技术”，未注意到对比文件 1 的公告时间在涉案申请的申请日之后，因此论述错误。此外，在该无效宣告理由中没有引用涉及的具体法条。', 146);
INSERT OR REPLACE INTO reference_materials (id, source_file, chunk_index, content, tokens) VALUES ('ref_6c5d2179d496', '2019年实务真题及答案解析.pdf', 40, '# 2、对于理由2的分析

理由 2 认为权利要求 1 相对于对比文件 2 不具备新颖性, 结论是成立的, 但在评述中遗漏了 “压筒底部设有多个出蒜孔” 这一特征。另外, 在该无效宣告理由中没有引用涉及的具体法条, 存在撰写不规范的问题。', 119);
INSERT OR REPLACE INTO reference_materials (id, source_file, chunk_index, content, tokens) VALUES ('ref_7a0b746d555b', '2019年实务真题及答案解析.pdf', 41, '# 3、对于理由3的分析

理由 3 认为权利要求 2-3 相对于对比文件 2 不具有新颖性。对比文件 2 已经公开了从属权利要求 2-3 的附加技术特征，在其引用的权利要求不具备新颖性的前提下，从属权利要求 2-3 也均不具备新颖性。理由 3 的结论是成立的，但没有针对所述技术方案的具体对比，存在论述缺陷。此外，在该无效宣告理由中没有引用涉及的具体法条，存在撰写不规范的问题。', 190);
INSERT OR REPLACE INTO reference_materials (id, source_file, chunk_index, content, tokens) VALUES ('ref_a8e8642a1869', '2019年实务真题及答案解析.pdf', 42, '# 4、对于理由4的分析

理由 4 认为权利要求 4 相对于对比文件 1 和对比文件 2 结合不具有创造性，理由错误。对比文件 1 是申请日在涉案专利的申请日之前，授权公告日在涉案专利的申请日之后，向中国国家知识产权局专利局提交的实用新型专利，不属于现有技术，不能作为对比文件单独或与其他对比文件结合来评价一项权利要求的创造性，故理由 4 的结论是不成立的。', 180);
INSERT OR REPLACE INTO reference_materials (id, source_file, chunk_index, content, tokens) VALUES ('ref_834944614357', '2019年实务真题及答案解析.pdf', 43, '# 5、对于理由 5 的分析

理由 5 客户认为权利要求 4 相对于对比文件 2 不具有创造性。

在权利要求 4 中，所述压盘上设有多个压蒜齿，从压筒上方向下方碾压蒜瓣，其作用是使得挤压更加充分，从而将残留的蒜瓣挤碎，提高蒜泥的挤出效率。而对比文件 2 公开的压蒜装置，是当出现细碎蒜粒堵塞漏孔的现象时，反向（即图 1 中逆时针方向）转动上压杆 1，使另一侧的第二压板 7 向压料筒 5 底面运动，从压料筒的底部向上顶出堵塞的蒜粒，从而将堵塞的漏孔疏通。因此在结构、作用、以及解决的技术问题方面均不相同，本领域的技术人员没有动机在对比文件 2 中的第一压板上进行同样的设置。因此，权利要求 4 相对于对比文件 2 不具备创造性的无效宣告理由不成立。', 326);
INSERT OR REPLACE INTO reference_materials (id, source_file, chunk_index, content, tokens) VALUES ('ref_1b3a8ac0003a', '2019年实务真题及答案解析.pdf', 44, '# 6. 对于理由 6 的分析

《专利法实施细则》第 65 条第 2 款规定了无效宣告请求理由所涵盖的具体法律条款，但《专利法实施细则》第 22 条第 1 款并不属于所规定的范畴。因此，根据上述规定，不能以从属权利要求的主题名称与其引用的权利要求的主题名称不一致作为无效理由，不能以《专利法实施细则》第 22 条第 1 款的规定为由提出无效宣告请求，理由 6 不成立。', 185);
INSERT OR REPLACE INTO reference_materials (id, source_file, chunk_index, content, tokens) VALUES ('ref_4a0424f15a12', '2019年实务真题及答案解析.pdf', 45, '# 7、对于理由 7 的分析

理由 7 中，客户认为权利要求 4 的概括得不到说明书的支持，理由成立。在涉案专利说明书第 9 段指出：“压蒜器的压盘 32 的下表面为平面，在使用时，压蒜器将蒜瓣压扁后，仍有部分蒜瓣被压成饼状残留在压筒 4 内，即便反复施力挤压仍无法将残留的蒜瓣挤碎并排出压筒 4。为进一步解决蒜瓣残留的问题，……在压盘 32 的下表面上设置多个与出蒜孔 5 对应的压蒜齿 33，所述多个压蒜齿 33……其横截面直径小于出蒜孔 5 的内径……从而使得挤压更加充分，提高了蒜泥的挤出效率。”而在该权利要求的附加技术特征中仅仅在压盘上设有压蒜齿，既没有限定“压蒜齿的大小”，也没有限定“压蒜齿的位置”，其涵盖了当压蒜齿与出蒜孔位置不对应或压蒜齿的直径大于等于出蒜孔的内径时，导致压蒜齿无法进入出蒜孔内的技术方案，而这些技术方案无法解决挤压充分、提高蒜泥挤出效率的问题。因此，权利要求 4 保护的技术方案得不到说明书的支持，不符合《专利法》第 26 条第 4 款的规定。', 441);
INSERT OR REPLACE INTO reference_materials (id, source_file, chunk_index, content, tokens) VALUES ('ref_567325ec3347', '2019年实务真题及答案解析.pdf', 48, '# 1、在第一题已经分析过的无效理由

在第一题分析的基础上，较为容易地可确定无效理由为：

① 权利要求 1 相对于对比文件 1 不具有新颖性；  
② 权利要求 1 相对于对比文件 2 不具有新颖性；  
③ 权利要求 2 相对于对比文件 2 不具有新颖性；  
④ 权利要求 3 相对于对比文件 2 不具有新颖性；  
⑤ 权利要求 4 没有以说明书为依据。', 182);
INSERT OR REPLACE INTO reference_materials (id, source_file, chunk_index, content, tokens) VALUES ('ref_f8cf5c28d116', '2019年实务真题及答案解析.pdf', 49, '# 2、其他无效理由分析

权利要求 4 的附加技术特征中，对 “压盘” 作了进一步限定，然而在引用权利要求 2 时，在先权利要求的技术方案中并没有出现 “压盘”，因而缺少引用基础，导致权利要求 4 引用权利要求 2 时，技术方案不清楚，不符合《专利法》第 26 条第 4 款的规定。这个缺陷可以作为无效理由。

另外，根据说明书背景技术记载，现有的压蒜器用于挤压配合的压头3''和压筒4''分开的角度有限，蒜瓣较大时不易放入，而且压杆长度有限，挤压较大的蒜瓣时仍然比较费劲。因此上、下压杆的前端活动连接是解决这一技术问题的必要技术特征，而权 1 缺少这一必要特征，可以作为无效理由。

其他无效理由可参考官方答案，考生较难想到写在无效请求书中。考生按照下面的推荐答案掌握即可。', 339);
INSERT OR REPLACE INTO reference_materials (id, source_file, chunk_index, content, tokens) VALUES ('ref_9c95db075d75', '2019年实务真题及答案解析.pdf', 51, '# 一、撰写权利要求书的六步法

2019 年专利代理实务考试的第三题要求应试者根据题目给出的技术交底材料（附件 3），并综合考虑附件 1 和对比文件 1-2 所反映的现有技术，为客户撰写一份发明专利申请的权利要求书。考生注意，如果认为并列发明点需要写出多份专利申请的，第二件申请应当写在第五题。

第三题按照删除式六步法，撰写思路如下：', 169);
INSERT OR REPLACE INTO reference_materials (id, source_file, chunk_index, content, tokens) VALUES ('ref_98b2153ca468', '2019年实务真题及答案解析.pdf', 52, '# 第一步：分析技术特征

（1）删除非技术特征，可写入到权利要求中的特征包括：

第一实施例:

① 压蒜器，包括上压杆 1 和下压杆 2，上压杆 1 与下压杆 2 在两者的前端部活动连接；  
② 在上压杆 1 靠近前端部的位置设有压蒜部件 3，压蒜部件 3 包括压臂 31 和压盘 32；  
③ 在下压杆 2 上相应设有压筒 4;  
④ 压筒 4 包括壳体 41 和可拆卸的内筒 42;  
⑤ 壳体 41 为上下两端开口的筒状结构，其位置靠近下压杆 2 前端，壳体 41 与下压杆 2 连为一体；  
⑥ 内筒 42 上端开口，内筒 42 底部开设有多个出蒜孔 5;  
⑦ 内筒 42 的上端边缘设有外翻的折边 42a。

第二实施例:

⑧ 所述压蒜器的压筒 4 包括壳体 41 和可拆卸的插片 42;  
⑨ 壳体 41 为上下两端开口的筒状结构，它与下压杆 2 连为一体，位置靠近下压杆 2 前端；  
⑩ 在壳体 41 下端沿垂直于壳体 41 轴线的方向开设有插槽 41a，在插槽 41a 下方、壳体 41 内壁面上设有一圈环形的凸起 41b，所述凸起 41b 从壳体 41 的内壁面沿径向向内延伸；  
⑪ 插片 42 的形状大小与壳体 41 内部横截面基本一致，插片 42 设置有多个出蒜孔 5，插片 42 的一侧边缘设置有便于插拔插片 42 的把手 42b。', 593);
INSERT OR REPLACE INTO reference_materials (id, source_file, chunk_index, content, tokens) VALUES ('ref_157764d024b1', '2019年实务真题及答案解析.pdf', 53, '# 第三实施例

⑫ 所述压蒜器的压筒 4 包括壳体 41 和可拆卸的出蒜筒 42;  
⑬ 壳体 41 为上下两端开口的筒状结构，它与下压杆 2 连为一体，位置靠近下压杆 2 前端；  
⑭ 出蒜筒 42 为上端开口的筒体结构，出蒜筒 42 的底板上设置多个出蒜孔 5；  
⑮ 在壳体 41 靠近下端的外壁面设有外螺纹，出蒜筒 42 的内壁设有与壳体 41 上外螺纹相配合的内螺纹。出蒜筒 42 通过螺纹连接在壳体 41 的下端。', 217);
INSERT OR REPLACE INTO reference_materials (id, source_file, chunk_index, content, tokens) VALUES ('ref_9313ff6f1a88', '2019年实务真题及答案解析.pdf', 54, '# 第二发明点

⑯ 上压杆 1 的中后段设置有圆弧状的下凹部 1a;  
