INSERT OR REPLACE INTO reference_materials (id, source_file, chunk_index, content, tokens) VALUES ('ref_dfb5cffda4a0', '2019年实务真题及答案解析.pdf', 55, '# (2) 技术逻辑分析

前三个实施例，需要找出能替代的可拆卸的内筒，可拆卸的插片，可拆卸的出蒜筒。根据最后一段的提示，可使用“出蒜部件”。如果没发现材料的提示，也可以概括为“可拆卸盛蒜部件”、“放

