INSERT OR REPLACE INTO reference_materials (id, source_file, chunk_index, content, tokens) VALUES ('ref_dc536d4aeb6f', '2019年实务真题及答案解析.pdf', 57, '# 第三步：确定第一件申请发明点所要解决的技术问题

现有的压蒜器的压料筒与下手柄是一体的，不容易对压料筒内残留的蒜末进行清理，有时会有蒜沫残余，导致不够卫生。', 80);
INSERT OR REPLACE INTO reference_materials (id, source_file, chunk_index, content, tokens) VALUES ('ref_b3774436c5a4', '2019年实务真题及答案解析.pdf', 58, '# 第四步：确定第一件申请的必要技术特征

第①、第②、第③个特征中，压蒜器，包括上压杆1和下压杆2，上压杆1与下压杆2在两者的前端部活动连接；在上压杆1靠近前端部的位置设有压蒜部件3，压蒜部件3包括压臂31和压盘32；在下压杆2上相应设有压筒4，都是构成压蒜器的必要特征，也是解决技术问题的必要特征；

第④、第⑧、第⑫个特征概括为出蒜部件，是发明点，也是必要技术特征。

第⑤、⑨、⑬个特征实质内容相同，都是壳体的形状和连接关系，选择其中一个说法作为必要技术特征：壳体41为上下两端开口的筒状结构，其位置靠近下压杆2前端，壳体41与下压杆2连为一体；

第⑥个特征，内筒 42 上端开口不是必要特征，但是内筒 42 底部开设有多个出蒜孔 5 是解决问题的必要特征。撰写独立权利要求时，需要注意将内筒替换为出蒜部件。

其余特征均为具体结构，或者其他发明点，均不是必要特征。', 388);
INSERT OR REPLACE INTO reference_materials (id, source_file, chunk_index, content, tokens) VALUES ('ref_72cf386b2fbb', '2019年实务真题及答案解析.pdf', 59, '# 第五步：撰写第一件申请的独立权利要求

将上述必要特征组合，加入其特征在于，即独立权利要求：

1、一种压蒜器，包括上压杆（1）和下压杆（2），上压杆（1）与下压杆（2）在两者的前端部活动连接；在上压杆（1）靠近前端部的位置设有压蒜部件（3），压蒜部件（3）包括压臂（31）和压盘（32）；在下压杆（2）上相应设有压筒（4），其特征在于，压筒（4）包括壳体（41）和可拆卸的出蒜部件；壳体（41）为上下两端开口的筒状结构，其位置靠近下压杆（2）前端，壳体（41）与下压杆（2）连为一体；出蒜部件底部开设多个出蒜孔。', 259);
INSERT OR REPLACE INTO reference_materials (id, source_file, chunk_index, content, tokens) VALUES ('ref_7d488a5b967d', '2019年实务真题及答案解析.pdf', 60, '# 第六步：撰写第一件申请的从权

出蒜部件的三种具体形式各为一个权利要求，未写入独立权利要求的各特征均写入从权：

“2、根据权利要求 1 所述的压蒜器，其特征在于，所述出蒜部件为内筒，内筒上部开口，内筒

（42）的上端边缘设有外翻的折边（42a），内筒底部开设有多个出蒜孔。

3、根据权利要求 1 所述的压蒜器, 其特征在于, 所述出蒜部件为可拆卸的插片 (42), 插片 (42) 设置有多个出蒜孔 (5)。  
4、根据权利要求 3 所述的压蒜器，其特征在于，在壳体（41）下端沿垂直于壳体（41）轴线的方向开设有插槽（41a），在插槽（41a）下方、壳体（41）内壁面上设有一圈环形的凸起（41b），所述凸起（41b）从壳体（41）的内壁面沿径向向内延伸。  
5、根据权利要求 4 所述的压蒜器，其特征在于，插片（42）的形状大小与壳体（41）内部横截面基本一致，插片（42）的一侧边缘设置有便于插拔插片（42）的把手（42b）。  
6、根据权利要求 1 所述的压蒜器，其特征在于，所述出蒜部件为出蒜筒（42），出蒜筒（42）为上端开口的筒体结构，出蒜筒（42）的底板上设置多个出蒜孔（5）。  
7、根据权利要求 6 所述的压蒜器，其特征在于，在壳体（41）靠近下端的外壁面设有外螺纹，出蒜筒（42）的内壁设有与壳体（41）上外螺纹相配合的内螺纹，出蒜筒（42）通过螺纹连接在壳体（41）的下端。  
8、根据权利要求 1 所述的压蒜器，其特征在于，上压杆（1）的中后段设置有圆弧状的下凹部（1a）。  
9、根据权利要求 8 所述的压蒜器，其特征在于，当压蒜部件（3）的压盘（32）处于压筒（4）底部时，下凹部（1a）的最低点略高于下压杆（2）的上表面。  
10、根据权利要求 1 所述的压蒜器，其特征在于，设置多个出蒜的部件，其出蒜孔尺寸不同，根据需要更换不同的出蒜部件。”', 800);
