INSERT OR REPLACE INTO reference_materials (id, source_file, chunk_index, content, tokens) VALUES ('ref_1a5471aa6a90', '2019年实务真题及答案解析.pdf', 62, '# （六）第二件申请撰写及单一性回答问题

第二个发明点是上压杆的中后段设置有下凹部。没有特殊情况，第二件申请的前序部分可以和第一件申请前序部分相同，特征部分写为第二个发明点。第五题推荐答案如下：

“1、一种压蒜器，包括上压杆（1）和下压杆（2），上压杆（1）与下压杆（2）在两者的前端部活动连接；在上压杆（1）靠近前端部的位置设有压蒜部件（3），压蒜部件（3）包括压臂（31）和压盘（32）；在下压杆（2）上相应设有压筒（4），其特征在于，上压杆（1）的中后段设置有下凹部（1a）。

两份专利申请分案的理由按照模板论述即可。

官方答案及推荐答案  
第一题', 282);
INSERT OR REPLACE INTO reference_materials (id, source_file, chunk_index, content, tokens) VALUES ('ref_a68fe666ba54', '2019年实务真题及答案解析.pdf', 63, '包括压臂（31）和压盘（32）；在下压杆（2）上相应设有压筒（4），其特征在于，上压杆（1）的中后段设置有下凹部（1a）。

两份专利申请分案的理由按照模板论述即可。

官方答案及推荐答案  
第一题

<table><tr><td>官方答案</td><td>推荐答案</td></tr><tr><td>尊敬的A公司:很高兴贵方委托我代理机构代为办理有关请求宣告专利号为ZL201721443567.x,名称为“压蒜器”的实用新型专利无效宣告请求的有关事宜。经仔细阅读贵方提供的附件1-2以及对比文件1-2,我认为附件2中各项理由是否成立的结论和理由是:</td><td>尊敬的A公司:现收到贵公司提供的B公司涉案专利、两份对比文件以及贵公司撰写的无效请求书,分析如下:</td></tr><tr><td>(一)关于新颖性和创造性1、权利要求1相对于对比文件1不具备新颖性的无效宣告理由成立对比文件1是向中国国家知识产权局专利局提交的实用新型专利申请,其申请日在涉案申请的申请日之前,授权公告日在涉案申请的申请日之后,且公开了涉案专利权利要求1的全部技术特征,构成了涉案专利的抵触申请,因此权利要求1相对于对比文件1不具备新颖性的结论是正确的。但在论述权利要求1不具备新颖性的原因时,指出“对比文件1作为现有技术”,未注意到对比文件1的公开时间在涉案申请的申请日之后,因此整体论述错误。此外,没有指明具体法条,撰写不够规范。</td><td>1、权利要求1相对对比文件1不具有新颖性结论正确对比文件1申请日为2017年11月22日,公开日为2018年6月30日,涉案专利申请日为2017年12月12日,因此对比文件1是申请在先,公开在后的中国实用新型专利,可以评价涉案专利的新颖性,不能评价创造性。对比文件1公开了一种家用压蒜器,包括两个手柄3组成(即上压杆和下压杆),一个手柄的前端连接压头1(即压蒜部件),另外一个手柄的前端连接压槽2(即压筒),两个手柄3通过铆钉4连接起来(即上压杆和下压杆活动连接),压槽2顶部开口,底部设有多个漏孔5(即压筒底部设有多个出蒜孔)。由此可见,权利要求1所要求保护的技术方案与对比文件1所公开的内容相比,技术方案实质上相同,二者均属于相同的压蒜器领域,所要解决的问题和产生的效果相同,均是挤压蒜瓣并使蒜泥从出蒜孔中挤出,因此对比文件1构成抵触申请,权利要求1相对于对比文件1不具备新颖性,不符合《专利法》第22条第2款的规定。因此,贵公司提出权利要求1相对对比文件1不具有新颖性结论正确,但是,贵公司所陈述的对比文件1为现有技术是错误的,对比文件1是申请在先公开在后的中国专利。其次,贵方进行技术特征对比之后,应当分析技术领域、解决的技术问题和产生的效果实质相同。另外,贵方也没有给出新颖性所涉及的法条,应当指出权利要求1不具有新颖性,不符合《专利法》第22条第2款的规定。</td></tr><tr><td>2、权利要求1相对于对比文件2不具备新颖性</td><td>2、权利要求1相对对比文件2不具有新颖性结</td></tr><tr><td>的无效宣告理由成立权利要求1相对于对比文件2不具备新颖性的结论是正确的,但在评述中没有遵循新颖性评价的技术特征单独对比原则,漏评了“压筒底部设有多个出蒜孔”这一技术特征,因此理由2中存在论述缺陷。此外,在该无效宣告理由中没有引用涉及的具体法条,存在撰写不规范的问题。</td><td>论正确对比文件2公开日早于涉案专利申请日,属于现有技术。对比文件2公开了一种防堵压蒜装置,包括上压杆1、下压杆2,第一压臂3,第一压板4和压料筒5。上压杆1和下压杆2的前端部通过销轴连接在一起(即上压杆和下压杆活动连接),上压杆靠近前端的位置活动安装有第一压臂3,第一压板4与第一压臂3焊接在一起(第一压臂和第一压板一起构成压蒜部件);下压杆2上对应设有压料筒5,压料筒5为顶部敞口的筒体,筒体底部设置多个漏孔(相当于权利要求1中压筒底部设有多个出蒜孔)。由此可见,权利要求1所要求保护的技术方案与对比文件2所公开的内容相比,技术方案实质上相同,二者均属于相同的压蒜器领域,所要解决的问题和产生的效果相同,均是挤压蒜瓣并使蒜泥从出蒜孔中挤出,因此权利要求1相对于对比文件2不具备新颖性,不符合《专利法》第22条第2款的规定。因此,贵公司提出权利要求1相对对比文件1不具有新颖性结论正确。但是,贵方没有评述压筒底部设有多个出蒜孔,不符合新颖性同样的发明和实用新型的判断原则。其次,贵方进行技术特征对比之后,应分析技术领域、解决的技术问题和产生的效果实质相同。另外,贵方也没有给出新颖性所涉及的法条,应当指出权利要求1不具有新颖性,不符合《专利法》第22条第2款的规定。</td></tr><tr><td>3、权利要求2—3相对于对比文件2不具备新颖性的无效宣告理由成立理由3成立,但缺少针对所述技术方案的具体对比。此外,在该无效宣告理由中没有引用涉及的具体法条,存在撰写不规范的问题。</td><td>3、权利要求2-3相对对比文件2不具有新颖性结论正确权利要求2、3的附加特征都在对比文件2公开,权利要求2、3不具有新颖性理由和结论都正确。但是,贵方并没有在无效请求书中详细论述理由。无效请求书中应当结合对比文件详细分析权利要求2、3的附加特征已被对比文件2公开的具体理由,并指明不符合新颖性的法条。</td></tr><tr><td>4、权利要求4相对于对比文件2和1不具备创造性的无效宣告理由不成立由于对比文件1的授权公告日在涉案专利的申请日之后,不能构成现有技术,因此不能作为对比文件,单独或与其他对比文件结合来评价一项权利要求的创造性。故理由4的结论是不成立的。此外,在该无效宣告理由中没有引用涉及的具体法条,存在撰写不规范的问题。</td><td>4、权利要求4相对对比文件1、2结合不具有创造性理由和结论均不成立对比文件1是申请在先,公开在后的中国实用新型专利,不能和其他文件组合评价创造性,贵公司认为权利要求4相对对比文件1、2的结合不具有创造性结论错误。</td></tr><tr><td>5、权利要求4相对于对比文件2不具备创造性的无效宣告理由不成立在权利要求4中,所述压盘上设有多个压蒜齿的作用是使得挤压更加充分,从而将残留的蒜瓣挤碎,提高蒜泥的挤出效率;而对比文件2公开的压蒜装置,其第二压板上的若干凸起且与漏孔一一对应,但其作用是疏通漏孔,防止压料筒的漏孔被压制的细碎蒜粒堵塞,并不参与碎蒜操作,与涉案专利中压蒜齿的要解决的技术问题和/或所起的功能作用均不相同,本领域的技术人员没有动机在对比文件2中的第一压板上进行同样的设置。因此,权利要求4相对于对比文件2不具备创造性的无效宣告理由不成立。此外,在该无效宣告理由中没有引用涉及的具体法条,存在撰写不规范的问题。</td><td>5、权利要求4相对对比文件2不具有创造性结论不成立权利要求4是对权利要求2或权利要求3的进一步限定,其附加特征是“压盘(32)上设有多个压蒜齿(33)”,对比文件2中的第一压板4相当于压盘32,第一压板4上没有设置凸起。因此,“压盘(32)上设有多个压蒜齿(33)”属于区别技术特征。基于该区别特征,权利要求4所要解决的技术问题是进一步提高蒜泥的挤出效率。对比文件2中虽然公开了第二压板7上设置凸起8,但其起作用的方式是当出现细碎蒜粒堵塞漏孔的现象,反向(即图1中逆时针方向)转动上压杆1,使另一侧的第二压板7向压料筒5底面运动,从压料筒的底部向上顶出堵塞的蒜粒,从而将堵塞的漏孔疏通。因此在结构、作用、以及解决的技术问题方面均不相同,没有给出将第二压板上的凸起8设置在第一压板上的启示。由于涉案专利在压盘上设置了压蒜齿,在捣蒜的同时能够方便地将蒜泥从出蒜孔中挤出,因此具有进步。因此,对比文件2不能破坏权利要求4的创造性,权利要求4相对于对比文件2不具备创造性的无效宣告结论不成立。</td></tr><tr><td>(二)其他无效理由6、权利要求3和4不符合《专利法实施细则》第二十二条第一款的规定无效宣告理由不成立《专利法实施细则》第六十五条第二款规定了无效宣告请求的范围。根据上述规定,《专利法实施细则》第二十二条第一款不属于上述无效宣告请求的范围,即,理由6不成立。</td><td>6、权利要求3、4主题名称不一致不是无效理由《专利法实施细则》第22条第1款不属于《专利法实施细则》第65条第2款的规定无效理由,因此不能将权利要求3、4主题名称不一致作为无效理由。</td></tr><tr><td>7、权利要求4得不到说明书支持的无效宣告理由成立权利要求4的技术方案涵盖了,当压蒜齿与出蒜孔位置不对应或压蒜齿的直径大于等于出蒜孔的内径时,压蒜齿无法深入出蒜孔内的技术方案,上述技术方案无法解决充分挤压的问题。因此,权利要求4请求的技术方案得不到说明书的支持,即,权利要求4中除了应该限定“压蒜齿的大小”之外,还应当限定“压蒜齿的位置”。由此可知,理由7成立,但不支持的说理依据不足。此外,在该无效宣告理由中没有引用涉及的具体法条,存在撰写不规范的问题。</td><td>7、权利要求4得不到说明书的支持结论正确权利要求4概括地描述了压蒜齿的设置,根据说明书的记载,只有压蒜齿与出蒜孔位置对应,直径略小于出蒜孔直径,才能将残余的蒜压出。如果压蒜齿与出蒜孔位置不对应,或者压蒜齿的直径大于出蒜孔直径,则无法解决压出蒜瓣残留的技术问题,因此权利要求4未以说明书为依据,不符合《专利法》第26条第4款的规定。贵方分析结论正确,但没有详细分析权利要求未以说明书为依据的理由,也没有引用具体法条。</td></tr><tr><td>综上,目前贵公司撰写的无效宣告请求书存在一些瑕疵,建议根据上述分析进行修改。以上咨询意见仅供参考,有问题请与我们随时沟通。祝好!XXX专利代理机构XXXXXX又年XX月XX:日</td><td>因此,贵司提出的无效理由需要修改,才能提交。</td></tr></table>', 4142);
