INSERT OR REPLACE INTO reference_materials (id, source_file, chunk_index, content, tokens) VALUES ('ref_d30db261d490', '2019年实务真题及答案解析.pdf', 65, '意见仅供参考,有问题请与我们随时沟通。祝好!XXX专利代理机构XXXXXX又年XX月XX:日</td><td>因此,贵司提出的无效理由需要修改,才能提交。</td></tr></table>

第二题

<table><tr><td>官方答案</td><td>推荐答案</td></tr><tr><td>国家知识产权局:根据《专利法》第四十五条及《专利法实施细则》第六十五条的规定,请求人现请求宣告专利号为ZL201721443567.x,名称为“压蒜器”的实用新型专利全部无效,具体理由如下:</td><td>国家知识产权局:根据《专利法》第45条及《专利法实施细则》第65条的规定,现请求申请号为201721234567.X,名称为“压蒜器”的实用新型专利(以下简称该专利)无效。请求人使用的证据为:对比文件1:201721433456.5,申请日2017年11月22日,授权公告日2018年6月30日;对比文件2:201220789117.7,申请日2012年9月4日,授权公告日2013年3月23日。上述对比文件1的申请日早于该专利的申请日,授权公告日晚于该专利的申请日,属于申请在先,公开在后的中国专利,可评价权利要求新颖性。对比文件2的公开日早于该专利的申请日,构成该专利的现有技术,可评价权利要求新颖性和创造性。依据对比文件1至2,请求人请求宣告该专利无效的具体理由如下:</td></tr><tr><td>(一)关于新颖性和创造性1、权利要求1相对于对比文件1不具备《专利法》第二十二条第二款规定的新颖性权利要求1请求保护一种压蒜器。对比文件1(ZL201720433456.5)公开了一种家用压蒜器,具体公开了如下内容(参见说明书第[0005]段、附图1):家用压蒜器由压槽1、压头2及两个手柄3组成。压头1和压槽2分别设置在两个手柄3的前端(即,上压杆靠近前端的位置设有压</td><td>1、权利要求1相对于对比文件1不具有新颖性对比文件1申请日为2017年11月22日,公开日为2018年6月30日,涉案专利申请日为2017年12月12日,因此对比文件1是申请在先,公开在后的中国实用新型专利。对比文件1公开了一种家用压蒜器,包括两个手柄3组成(即上压杆和下压杆),一个手柄的前端连接压头1(即压蒜部件),另外一个手柄的前端连接压槽2(即压筒),两个手柄3通</td></tr><tr><td>蒜部件,下压杆上设有与压蒜部件相对应的压筒),手柄3中部设有连接孔,把两个手柄3通过连接孔用钥钉4连接起来(即上压杆和下压杆活动连接),压槽2顶部开口,底部有多个漏孔5。由此可见,对比文件1公开了权利要求1的全部技术特征,两者属于相同的技术领域,都解决了挤压蒜瓣时比较费力的技术问题,并能达到相同的节省力气的预期技术效果;且对比文件1的申请日为2017年11月22日,授权公告日为2018年09月30日,属于在涉案专利申请的申请日2017年12月12日以前向中国国家知识产权局专利局提出并且在该申请日后授权公告的实用新型专利。因而对比文件1构成了涉案专利权利要求1的抵触申请。因此,权利要求1相对于对比文件1不具备《专利法》第二十二条第二款规定的新颖性。</td><td>过铆钉4连接起来(即上压杆和下压杆活动连接),压槽2顶部开口,底部设有多个漏孔5(即压筒底部设有多个出蒜孔)。由此可见,权利要求1所要求保护的技术方案与对比文件1所公开的内容相比,技术方案实质上相同,二者均属于相同的压蒜器领域,所要解决的问题和产生的效果相同,均是挤压蒜瓣并使蒜泥从出蒜孔中挤出,因此对比文件1构成抵触申请,权利要求1相对于对比文件1不具备专利法规定的新颖性,不符合《专利法》第22条第2款的规定。</td></tr><tr><td>2、权利要求1相对于对比文件2不具备《专利法》第二十二条第二款规定的新颖性对比文件2(ZL201220789117.7)的授权公告日为2013年03月23日,早于该专利的申请日2017年12月12日,故对比文件2公开的技术内容构成涉案专利的现有技术。权利要求1请求保护一种压蒜器。对比文件2公开了一种防堵孔压蒜装置(参见对比文件2的说明书第[0005]至[0006]段、图1),包括有上压杆1、下压杆2、第一压臂3、第一压板4和压料筒5,上压杆1和下压杆2的前端端部通过销轴连接在一起(相当于涉案专利的权利要求1中的上压杆和下压杆活动连接),下压杆2上设有压料筒5(图1左侧靠近销轴连接的位置,即靠近前端的位置),压料筒5为顶部敞口的筒体,其底部设有供蒜泥通过的多个漏孔;第一压臂3与上压杆1在与压料筒5相对应的位置(图1所示上压杆1的下侧位置)活动连接,第一压板4与第一压臂3焊接在一起(第一压臂和第一压板一起相当于压蒜部件)。因此,对比文件2公开了权利要求1的全部技术特征,两者均属于家用压蒜器这一相同的技术领域,都解决了挤压蒜瓣时比较费力的技术问题,并能达到相同的节省力气的预期技术效果。故权利要求1相对于对比文件2不具备新颖性,不符合《专利法》第二十二条第二款的规定。</td><td>2、权利要求1相对于对比文件2不具有新颖性对比文件2公开日早于涉案专利申请日,属于现有技术。对比文件2公开了一种防堵压蒜装置,包括上压杆1、下压杆2,第一压臂3,第一压板4和压料筒5。上压杆1和下压杆2的前端部通过销轴连接在一起(即上压杆和下压杆活动连接),上压杆靠近前端的位置活动安装有第一压臂3,第一压板4与第一压臂3焊接在一起(第一压臂和第一压板一起构成压蒜部件);下压杆2上对应设有压料筒5,压料筒5为顶部敞口的筒体,筒体底部设有供蒜泥通过的多个漏孔(相当于压筒底部设有多个出蒜孔)。由此可见,权利要求1所要求保护的技术方案与对比文件2所公开的内容相比,技术方案实质上相同,二者均属于相同的压蒜器领域,所要解决的问题和产生的效果相同,均是均是挤压蒜瓣并使蒜泥从出蒜孔中挤出,权利要求1相对于对比文件2不具备新颖性,不符合《专利法》第22条第2款的规定。</td></tr><tr><td>3、权利要求2相对于对比文件2不具备《专利</td><td>3、权利要求2相对于对比文件2不具有新颖性</td></tr><tr><td>法》第二十二条第二款规定的新颖性从属权利要求2引用了权利要求1,对其所引用的权利要求作了进一步限定。而对比文件2还公开了(参见说明书第[0005]段)下述内容:上压杆1和下压杆2的前端端部通过销轴连接在一起[相当于权利要求2中上压杆(1)前端与下压杆(2)前端活动连接]。由此可知,对比文件2已经公开了从属权利要求2的附加技术特征,因此,在其引用的权利要求1不具备新颖性的前提下,从属权利要求2也不具备《专利法》第二十二条第二款规定的新颖性。</td><td>权利要求2进一步限定了“上压杆前端与下压杆前端活动连接”,对比文件2公开上压杆和下压杆的前端部通过销轴连接在一起(即前端活动连接的下位概念),在权利要求1不具有新颖性的情况下,权利要求2也不具有新颖性,不符合《专利法》第22条第2款的规定。</td></tr><tr><td>4、权利要求3相对于对比文件2不具备《专利法》第二十二条第二款规定的新颖性从属权利要求3引用了权利要求2,对其所引用的权利要求作了进一步限定。而对比文件2还公开了下述内容(参见说明书第[0005]段、图1):第一压臂3与上压杆1在与压料筒5相对应的位置(图1所示上压杆1的下侧位置)活动连接,第一压板4与第一压臂3焊接在一起[相当于权利要求3中的“所述压蒜部件(3)包括压臂(31)和固定连接在压臂(31)下端的压盘(32),所述压臂(31)的上端与上压杆(1)活动连接”。由此可知,对比文件2已经公开了从属权利要求3的全部附加技术特征,在其引用的权利要求2不具备新颖性的前提下,从属权利要求3也不具备《专利法》二十二条第二款规定的新颖性。</td><td>4、权利要求3相对于对比文件2不具有新颖性权利要求3进一步限定了“压蒜部件包括压臂和固定连接在压臂下端的压盘,压臂的上端与上压杆活动连接”,对比文件2公开第一压板4与第一压臂3焊接在一起(即压臂下端固定连接压盘),(即压臂的上端和上压杆活动连接)构成压蒜部,即公开了权利要求3的附加技术特征。在权利要求2不具有新颖性的情况下,权利要求3也不具有新颖性,不符合《专利法》第22条第2款的规定。</td></tr><tr><td>(二)其他无效宣告理由5、权利要求1缺少必要技术特征,不符合《专利法实施细则》第二十条第二款的规定该申请要解决的技术问题是蒜瓣较大时压蒜费劲,而通过改变其支点位置,也就是上、下压杆活动的连接位置,将其设置在上、下压杆的前端端部,增大了力臂,从而降低了所需要的操作力量,解决了压蒜费劲的技术问题。因而,将上、下压杆活动连接的位置设置在上、下压杆的前端端部,是涉案专利解决其压蒜费劲这一技术问题所不可缺少的技术特征,而权利要求1请求保护的方案没有针对该活动连接位置进行限定。因而,即权利要求1缺少解决其技术问题的必要技术特征,不符合《专利法实施细则》第二十条第二款的规定。</td><td>5、权利要求1缺少必要特征根据涉案专利背景技术的记载,现有的压蒜器用于挤压配合的压头3’和压筒4’分开的角度有限,蒜瓣较大时不易放入,而且压杆长度有限,挤压较大的蒜瓣时仍然比较费劲。具体实施方式最后一段描述,由于将支点的位置调整到上、下压杆的前端,本实用新型的压蒜器相比于现有的压蒜器操作更为省力,不需施加很大的握压力即可将蒜瓣压碎成蒜泥。因此,上压杆1前端与下压杆2前端活动连接是解决技术问题的必要技术特征,并未记载在权利要求1中。权利要求1缺少解决技术问题的必要技术特征,不符合《专利法实施细则》第20条第2款的规定。</td></tr><tr><td>6、权利要求1未以说明书为依据,不符合《专利法》第二十六条第四款的规定该申请要解决的技术问题是蒜瓣较大时压蒜费劲,而通过改变其支点位置,也就是上、下压杆活动的连接位置,将其设置在上、下压杆的前端端部,增大了力臂,从而降低了所需要的操作力量,解决了压蒜费劲的技术问题。而权利要求1请求保护的技术方案中涵盖了活动连接位置未设置在上、下压杆前端端部的技术方案,而这些技术方案,无法解决省力的技术问题。因此,权利要求1请求保护的技术方案得不到说明书的支持,不符合《专利法》第二十六条第四款有关权利要求应当以说明书为依据的规定。</td><td>(可略)</td></tr><tr><td>7、权利要求4请求保护的技术方案不清楚,不符合《专利法》第二十六条第四款的规定具体原因包括两个方面:第一,权利要求4请求保护的主题名称“压蒜部件”与其引用的权利要求2的主题名称“压蒜器”不一致,导致权利要求其请求保护的技术方案不清楚。第二,在权利要求4的附加技术特征中,对“压盘”作了进一步限定,然而在引用权利要求2时,在先权利要求的技术方案中并没有出现“压盘”,因而缺少引用基础,导致权利要求4引用权利要求2时,技术方案所要求保护的范围不清楚,不符合《专利法》第26条第4款的规定。【注】主题名称不一致不能作为无效理由,略。</td><td>6、权利要求4缺少引用基础在权利要求4的附加技术特征中,对“压盘”作了进一步限定,然而在引用权利要求2时,在先权利要求的技术方案中并没有出现“压盘”,因而缺少引用基础,导致权利要求4引用权利要求2时,技术方案所要求保护的范围不清楚,不符合《专利法》第26条第4款的规定。【注】主题名称不一致不能作为无效理由,略。</td></tr><tr><td>8、权利要求4请求保护的技术方案未以说明书为依据,不符合《专利法》第二十六条第四款的规定权利要求4中没有限定压蒜齿与出蒜孔相对位置,也没有限定两者的相对大小。如果两者位置不对应或者压蒜齿的直径大于或等于出蒜孔直径,那么压蒜齿将无法进入出蒜孔内,无法解决挤压充分、提高蒜泥挤出效率的技术问题。因此权利要求4得不到说明书的支持,不符合《专利法》第二十六条第四款有关权利要求应以说明书为依据的规定。</td><td>7、权利要求4未以说明书为依据权利要求4进一步限定了“压盘上设有多个压蒜齿”,其中“压蒜齿”概括了较宽的保护范围。根据说明书的记载,只有压蒜齿与出蒜孔位置对应,直径略小于出蒜孔直径,才能将残余的蒜压出。如果压蒜齿与出蒜孔位置不对应,或者压蒜齿的直径大于出蒜孔直径,则无法解决压出蒜瓣残留的技术问题,因此权利要求4未以说明书为依据,不符合《专利法》第26条第4款的规定。</td></tr><tr><td>综上所述,该实用新型专利不符合《专利法》第二十二条第二款、第二十六条第四款以及《专利法实施细则》第二十条第二款的规定,现请求宣告专利号为ZL201721443567.x,名称为“压蒜器”的实用新型专利全部无效。XX 专利代理机构 XXXXXXX 年 XX 月 XX 日</td><td>综上所述,本专利不符合《专利法》第22条第2款和《专利法》第26条第4款的规定,因此请求宣告该专利权全部无效。</td></tr></table>', 5425);
INSERT OR REPLACE INTO reference_materials (id, source_file, chunk_index, content, tokens) VALUES ('ref_3fd21e8bd074', '2019年实务真题及答案解析.pdf', 66, 'XXXXXX 年 XX 月 XX 日</td><td>综上所述,本专利不符合《专利法》第22条第2款和《专利法》第26条第4款的规定,因此请求宣告该专利权全部无效。</td></tr></table>

第三题', 105);
INSERT OR REPLACE INTO reference_materials (id, source_file, chunk_index, content, tokens) VALUES ('ref_8d54cac9ee28', '2019年实务真题及答案解析.pdf', 67, 'X 年 XX 月 XX 日</td><td>综上所述,本专利不符合《专利法》第22条第2款和《专利法》第26条第4款的规定,因此请求宣告该专利权全部无效。</td></tr></table>

第三题

<table><tr><td>官方答案</td><td>推荐答案</td></tr><tr><td>1.一种压蒜器,包括上压杆和下压杆,上压杆与下压杆在两者的前端部活动连接,在上压杆靠近前端部的位置设有压蒜部件,压蒜部件包括压臂和压盘,在下压杆上相应设有压筒,其特征在于,压筒包括与下压杆连为一体的壳体和可拆卸的出蒜部件,壳体为上下两端开口的筒状结构,出蒜部件上具有多个出蒜孔,所述出蒜部件可拆卸地安装在所述壳体上。</td><td>1、一种压蒜器,包括上压杆(1)和下压杆(2),上压杆(1)与下压杆(2)在两者的前端部活动连接;在上压杆(1)靠近前端部的位置设有压蒜部件(3),压蒜部件(3)包括压臂(31)和压盘(32);在下压杆(2)上相应设有压筒(4),其特征在于,压筒(4)包括壳体(41)和可拆卸的出蒜部件;壳体(41)为上下两端开口的筒状结构,其位置靠近下压杆(2)前端,壳体(41)与下压杆(2)连为一体;出蒜部件底部开设多个出蒜孔。</td></tr><tr><td>2.如权利要求1所述的压蒜器,其特征在于,所述出蒜部件为上端开口的内筒,所述内筒的上端边缘设有外翻的折边,内筒的底部开设有多个出蒜孔。</td><td>2、根据权利要求1所述的压蒜器,其特征在于,所述出蒜部件为内筒,内筒上部开口,内筒(42)的上端边缘设有外翻的折边(42a),内筒底部开设有多个出蒜孔。</td></tr><tr><td>3.如权利要求1所述的压蒜器,其特征在于,所述出蒜部件为形状大小与壳体内部横截面基本一致的插片,插片上设置有多个出蒜孔。</td><td>3、根据权利要求1所述的压蒜器,其特征在于,所述出蒜部件为可拆卸的插片(42),插片(42)设置有多个出蒜孔(5)。</td></tr><tr><td>4.如权利要求3所述的压蒜器,在所述壳体下端沿垂直于压筒轴线的方向开设有插槽,在插槽下方、壳体内壁面上设有一圈环形的凸起,插片从插槽插入壳体内。</td><td>4、根据权利要求3所述的压蒜器,其特征在于,在壳体(41)下端沿垂直于壳体(41)轴线的方向开设有插槽(41a),在插槽(41a)下方、壳体(41)内壁面上设有一圈环形的凸起(41b),所述凸起(41b)从壳体(41)的内壁面沿径向向内延伸。</td></tr><tr><td>5.如权利要求4所述的压蒜器,其特征在于,插片边缘设置有便于插拔插片的把手。</td><td>5、根据权利要求4所述的压蒜器,其特征在于,插片(42)的形状大小与壳体(41)内部横截面基本一致,插片(42)的一侧边缘设置有便于插拔插片(42)的把手(42b)。</td></tr><tr><td>6.如权利要求1所述的压蒜器,其特征在于,所述出蒜部件为上端开口的出蒜筒,出蒜筒的底板上设有多个出蒜孔,出蒜筒与壳体下端螺纹连接。</td><td>6、根据权利要求1所述的压蒜器,其特征在于,所述出蒜部件为出蒜筒(42),出蒜筒(42)为上端开口的筒体结构,出蒜筒(42)的底板上设置多个出蒜孔(5)。</td></tr><tr><td>7.如权利要求1—6任一项所述的压蒜器,其特征在于,包括出蒜孔尺寸不同的多个出蒜部件,根据需要更换不同的出蒜部件。</td><td>7、根据权利要求6所述的压蒜器,其特征在于,在壳体(41)靠近下端的外壁面设有外螺纹,出蒜筒(42)的内壁设有与壳体(41)上外螺纹相配合的内螺纹,出蒜筒(42)通过螺纹连接在壳体(41)的下端。</td></tr><tr><td>8.如权利要求1—6任一项所述的压蒜器,其特征在于,所述上压杆的中后段设置有下凹部,当压蒜部件的压盘处于压筒底部时,下凹部的最低点略高于下压杆的上表面。</td><td>8、根据权利要求1所述的压蒜器,其特征在于,上压杆(1)的中后段设置有圆弧状的下凹部(1a)。</td></tr><tr><td>9.如权利要求8所述的压蒜器,其特征在于,所述下凹部为圆弧形。</td><td>9、根据权利要求8所述的压蒜器,其特征在于,当压蒜部件(3)的压盘(32)处于压筒(4)底部时,下凹部(1a)的最低点略高于下压杆(2)的上表面。</td></tr><tr><td></td><td>10、根据权利要求1所述的压蒜器,其特征在于,设置多个出蒜的部件,其出蒜孔尺寸不同,根据需要更换不同的出蒜部件。</td></tr></table>', 1944);
INSERT OR REPLACE INTO reference_materials (id, source_file, chunk_index, content, tokens) VALUES ('ref_33949431a864', '2019年实务真题及答案解析.pdf', 68, '/td></tr><tr><td></td><td>10、根据权利要求1所述的压蒜器,其特征在于,设置多个出蒜的部件,其出蒜孔尺寸不同,根据需要更换不同的出蒜部件。</td></tr></table>

第四题', 105);
INSERT OR REPLACE INTO reference_materials (id, source_file, chunk_index, content, tokens) VALUES ('ref_87cdeb1166b7', '2019年实务真题及答案解析.pdf', 69, '/tr><tr><td></td><td>10、根据权利要求1所述的压蒜器,其特征在于,设置多个出蒜的部件,其出蒜孔尺寸不同,根据需要更换不同的出蒜部件。</td></tr></table>

第四题

<table><tr><td>官方答案</td><td>推荐答案</td></tr><tr><td>1. 权利要求 1 具备《专利法》第二十二条第二款规定的新颖性附件 1 没有公开权利要求 1 中“压筒包括与下压杆连为一体的壳体和可拆卸的出蒜部件,壳体为上下两端开口的筒状结构,所述出蒜部件可拆卸地安装在所述壳体上”技术特征,因此权利要求 1 的技术方案与附件 1 所公开的技术方案实质不同,因此权利要求 1 相对于附件 1 具备新颖性,符合《专利法》第二十二条第二款的规定。对比文件 1 没有公开权利要求 1 中“上压杆与下压杆在两者的前端部连接,压筒包括与下压杆连为一体的壳体和可拆卸的出蒜部件,壳体为上下两端开口的筒状结构,所述出蒜部件可拆卸地安装在所述壳体上”技术特征,因此权利要求 1 的技术方案与对比文件 1 所公开的技术方案实质不同,因此权利要求 1 相对于对比文件 1 具备新颖性,符合《专利法》第二十二条第二款的规定。对比文件 2 没有公开权利要求 1 中“压筒包括与下压杆连为一体的壳体和可拆卸的出蒜部件,壳体为上下两端开口的筒状结构,所述出蒜部件可拆卸地安装在所述壳体上”技术特征,因此权利要求 1 的技术方案与对比文件 2 所公开的技术方案实质不同,因此权利要求 1 相对于对比文件 2 具备新颖性,符合《专利法》第二十二条第二款的规定。</td><td>1、权利要求 1 具有新颖性涉案专利没有公开权利要求 1 中的特征“压筒(4)包括壳体(41)和可拆卸的出蒜部件”,因此撰写的独立权利要求相对涉案专利具有新颖性,符合《专利法》第 22 条第 2 款的规定。对比文件 1 没有公开权利要求 1 中的特征“压筒(4)包括壳体(41)和可拆卸的出蒜部件”,因此撰写的独立权利要求相对对比文件 1 具有新颖性,符合《专利法》第 22 条第 2 款的规定。对比文件 2 没有公开权利要求 1 中的特征“压筒(4)包括壳体(41)和可拆卸的出蒜部件”,因此撰写的独立权利要求相对对比文件 2 具有新颖性,符合《专利法》第 22 条第 2 款的规定。</td></tr><tr><td>2. 权利要求 1 具备《专利法》第二十二条第三款规定的创造性附件 1 与对比文件 1 和对比文件 2 的技术领域相同,都属于将蒜瓣压制成蒜泥的压蒜器。与对比文件1、2相比,附件1公开本申请的技术特征最多(具体分析省略),因此附件1可作为本申请最接近的现有技术。独立权利要求1与附件1公开的技术方案的区别在于:附件1没有公开权利要求1中的特征“压筒包括与下压杆连为一体的壳体和可拆卸的出蒜部件,壳体为上下两端开口的筒状结构,所述出蒜部件可拆卸地安装在所述壳体上”,根据该区别技术特征,权利要求1实际解决的技术问题是清洗不方便,对比文件1和2均没有公开上述区别技术特征,也没有给出设置可拆卸的出蒜部件以解决上述技术问题的启示,权利要求1的技术方案不是显而易见的,具备突出的实质性特点。权利要求1的技术方案通过设置可拆卸的出蒜部件,从而方便取出出蒜部件,对残留物进行清洗,具有有益的技术效果。因此,权利要求1相对于附件1、对比文件1、2或其结合,具有突出的实质性特点和显著的进步,具备创造性,符合《专利法》第二十二条第三款的规定。</td><td>2、权利要求 1 具有创造性涉案专利与本申请技术领域相同,公开的技术特征最多,所要解决的技术问题最为接近,是最接近的现有技术。独立权利要求1与涉案专利相比,区别在于,“压筒(4)包括壳体(41)和可拆卸的出蒜部件”。根据该区别技术特征,权利要求1实际解决的技术问题是现有技术的压料筒和手柄一体,不容易对压料筒内的残留蒜沫进行清理。对比文件1、2均没有公开上述区别技术特征,也没有给出设置可拆卸的出蒜部件以解决上述技术问题的启示,权利要求1的技术方案不是显而易见的,具备突出实质性特点。权利要求1的技术方案通过设置可拆卸的出蒜部件,从而方便取出出蒜部件,对残留物进行清洗,具有有益的技术效果。因此,权利要求1相对于涉案专利、对比文件1、2或其结合,具有突出的实质性特点和显著的进步,具备创造性,符合《专利法》第22条第3款的规定。</td></tr></table>', 1857);
INSERT OR REPLACE INTO reference_materials (id, source_file, chunk_index, content, tokens) VALUES ('ref_7c3a8a4b5faf', '2019年实务真题及答案解析.pdf', 70, '清洗,具有有益的技术效果。因此,权利要求1相对于涉案专利、对比文件1、2或其结合,具有突出的实质性特点和显著的进步,具备创造性,符合《专利法》第22条第3款的规定。</td></tr></table>

第五题

<table><tr><td>官方答案</td><td>推荐答案</td></tr><tr><td>1.一种压蒜器,包括上压杆和下压杆,上压杆与下压杆活动连接,在上压杆靠近前端部的位置设有压蒜部件,所述压蒜部件包括压臂和压盘,在下压杆上相应设有压筒,所述压筒上端开口、底部设有多个出蒜孔,其特征在于,所述上压杆中后段设置有下凹部,当压蒜部件的压盘处于压筒底部时,下凹部最低点略高于下压杆的上表面。</td><td>1、一种压蒜器,包括上压杆(1)和下压杆(2),上压杆(1)与下压杆(2)在两者的前端部活动连接;在上压杆(1)靠近前端部的位置设有压蒜部件(3),压蒜部件(3)包括压臂(31)和压盘(32);在下压杆(2)上相应设有压筒(4),其特征在于,上压杆(1)的中后段设置有下凹部(1a)。</td></tr><tr><td colspan="2">需要提出两份专利申请的理由:第一份申请的独立权利要求相对于现有技术作出贡献的技术特征是“压筒(4)包括壳体(41)和可拆卸的出蒜部件”,从而解决清洗不方便的技术问题。第二份申请的独立权利要求相对于现有技术作出贡献的技术特征是“上压杆(1)的中后段设置有下凹部”,从而解决压杆为直杆,不方便单手操作的技术问题。由此可见,两个独立权利要求对现有技术作出贡献的技术特征既不相同,彼此之间在技术上也无相互关联,从而两个独立权利要求之间并不包含相同或相应的特定技术特征,不属于一个总的发明构思,彼此之间不具备单一性,不符合《专利法》第31条的规定,因此应当分别作为两份专利申请提出。</td></tr></table>', 790);